const i=$input.first().json;const t=i.tenant||{};
if(!t.business_id) throw new Error('Missing tenant.business_id');
const date=String(i.date||'').slice(0,10);
if(!/^\d{4}-\d{2}-\d{2}$/.test(date)) throw new Error('Missing/invalid date (YYYY-MM-DD)');
let q='?select=starts_at,ends_at,status,doctor_id,service_id&business_id=eq.'+t.business_id+'&starts_at=gte.'+date+'T00:00:00&starts_at=lt.'+date+'T23:59:59&status=in.(scheduled,confirmed)&order=starts_at.asc';
if(i.doctor_id) q+='&doctor_id=eq.'+i.doctor_id;
if(i.service_id) q+='&service_id=eq.'+i.service_id;
return {json:{business_id:t.business_id,date,url:'https://zjathejcdkpxjyvululp.supabase.co/rest/v1/appointments'+q}};

const rows=$input.all().map(x=>x.json).filter(r=>r&&r.starts_at);
const booked=rows.map(r=>r.starts_at);const p=$('PREPARE').first().json;
return {json:{success:true,date:p.date,booked_count:booked.length,booked_slots:booked,
 message: booked.length? ('المواعيد المحجوزة في '+p.date+': '+booked.length+'. اقترح وقتاً متاحاً خارج هذه الأوقات ضمن مواعيد العمل.') : ('لا توجد حجوزات في '+p.date+' — كل المواعيد متاحة ضمن مواعيد العمل.')}};
